// Projection constants (must match WorldMap.tsx)
const LAT_MIN = -60;
const LAT_MAX = 85;
const PAD_TOP = 30;
const MAP_H = 550;

export function projectPoint(lat: number, lng: number): [number, number] {
  const clampedLat = Math.max(LAT_MIN, Math.min(LAT_MAX, lat));
  const x = ((lng + 180) / 360) * 1000;
  const y = PAD_TOP + ((LAT_MAX - clampedLat) / (LAT_MAX - LAT_MIN)) * MAP_H;
  return [x, y];
}

